script:
export const meta = {
  name: 'pass9-assess',
  description: 'Pass-9 adversarial assessment: actual-CI-execution + pass-8 fix-regression + standing dims',
  phases: [{ title: 'Assess' }, { title: 'Refute' }],
}

const REPO = '/Users/[REDACTED]/hc-assay'

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['id', 'severity', 'title', 'location', 'claim', 'why_real', 'suggested_fix'],
        properties: {
          id: { type: 'string' },
          severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low'] },
          title: { type: 'string' },
          location: { type: 'string' },
          claim: { type: 'string' },
          why_real: { type: 'string' },
          suggested_fix: { type: 'string' },
        },
      },
    },
  },
}

const COMMON = `You are an adversarial production-readiness assessor for the hc-assay engine at ${REPO} (a dataset-agnostic, data-sovereign empirical-ML/methodology engine; optional backends import-guarded; transcripts committed + scrubbed intentionally). It has survived EIGHT hardening passes and CI is currently green — easy findings are gone. Report ONLY genuine, concrete, FALSIFIABLE production-readiness defects with a real failure mode and a file:line/symbol location; no style nits. If a dimension is clean, return few/zero findings — do NOT invent. Read real code (Read/Grep/Bash; "python -m pytest", "source .venv/bin/activate"). The branch is harden/pass-9 (just branched from merged main @ pass 8).`

const DIMENSIONS = [
  { key: 'CIEXEC', label: 'actual CI execution (NEW priority)', focus: `NEW DIMENSION born from pass 8: the assessment repeatedly checked CODE but never whether CI actually runs green, so CI was silently red for ~3 passes. Inspect the REAL CI: read .github/workflows/ci.yml and reason about each lane's EXACT command as it runs in CI (bare \`pytest\` not \`python -m pytest\`; the no-extras \`core\` lane with ONLY requirements-core.lock installed; the cold-cache \`uv\` resolve; the matrix py3.11–3.14). Look for: tests that import optional backends WITHOUT pytest.importorskip and would fail in the no-extras core lane (grep tests for bare \`import\`/\`from\` of opentelemetry/httpx/mlflow/langgraph/langchain_ollama/qdrant_client/psycopg/numpy/anyio/phoenix/claude_agent_sdk/openinference NOT preceded by importorskip); any gate that can pass vacuously or fail nondeterministically; any lane whose install step could fail on hashes; coverage/audit/license gate gaps. You may run \`gh run list --branch main\` / \`gh run view\` to inspect actual outcomes. A test that only runs in one lane and is unguarded for another is a finding.` },
  { key: 'FIXREG8', label: 'pass-8 fix-regression audit', focus: `Audit pass-8's OWN changes for follow-on defects (git log main; the K-* fixes). Scrutinize: (1) tracing.py SIGTERM re-delivery — the handler now does signal.signal(SIGTERM, SIG_DFL) + os.kill(getpid, signum); is there a re-entrancy/double-flush risk, a window where a second SIGTERM does nothing, or an issue when prior is SIG_IGN? (2) _local.py is_local_socket_path — can a crafted value like "/" alone, "/\\t..", or "host=/ " bypass intent or wrongly accept a remote? does the leading-"/" check interact badly with the authority branch? (3) pipeline.py _log_trail default=str — does it now MASK a real serialization bug, or stringify something that should error? does the warning leak secrets into logs? (4) the .uv-exclude-newer scheme — is the date parsing robust (CRLF, missing file)? could a stale date silently pin known-vulnerable deps that pip-audit then flags, or hide a security update? (5) the comment-stripping diff — could it now MISS a real lock divergence (e.g. a hash change on a commented line)? (6) coverage fail_under in pyproject — does it break any \`pytest\` invocation that lacks --cov (fail_under with no coverage data errors)?` },
  { key: 'PRIV', label: 'privacy/PII', focus: `Re-probe scripts/capture_transcripts.py + the committed corpus for any remaining operator-identity vector or new secret/PII class. The separator-flexible handle regex, IGNORECASE name tokens, ReDoS, and zero-pattern-derivation contexts were covered in pass 7 — look for anything NEW (other identities, hostnames, IPs, tokens, the .uv-exclude-newer or new files leaking anything).` },
  { key: 'SEC', label: 'security/data-sovereignty', focus: `Local-URI guards across ALL backends, injection, unsafe deserialization (pickle/yaml), path traversal, SSRF, secret handling. Now that K-SEC-1 opened Unix sockets, re-audit _local.py for a bypass.` },
  { key: 'CONC', label: 'correctness/concurrency/reliability', focus: `Races, the reasoning thread pool, cancellation/timeout, resource leaks (fds/connections/subprocesses/threads), partial-failure, retry/backoff, run_study idempotency.` },
  { key: 'METHOBS', label: 'methodology integrity + observability/provenance', focus: `Pre-registration firewall/HARKing prevention, canonical_hypothesis_digest binding, confirm primitives, provenance trail integrity (append-only/keyed/tamper-evident), MLflow lifecycle, structured logging not leaking secrets, env-var parsing.` },
]

phase('Assess')
const refuteSchema = {
  type: 'object', additionalProperties: false, required: ['verdict', 'reasoning'],
  properties: { verdict: { type: 'string', enum: ['STANDS', 'REFUTED'] }, reasoning: { type: 'string' } },
}

const perDim = await parallel(
  DIMENSIONS.map((d) => () =>
    agent(`${COMMON}\n\nYOUR DIMENSION: ${d.label}.\n${d.focus}`, {
      label: `assess:${d.key}`, phase: 'Assess', schema: FINDINGS_SCHEMA,
    }).then((r) => ({ dim: d.key, findings: (r && r.findings) || [] }))
  )
)
const all = perDim.filter(Boolean).flatMap((r) => r.findings.map((f) => ({ ...f, dim: r.dim })))
log(`Assess: ${all.length} raw findings`)

phase('Refute')
const judged = await parallel(
  all.map((f) => () =>
    agent(
      `You are an adversarial skeptic. Try to REFUTE this pass-9 finding about ${REPO} by reading the actual code. REFUTED if false, already-mitigated, out-of-scope by design (dataset-agnostic engine, optional import-guarded backends, intentionally-committed scrubbed transcripts, data-sovereign on-box, documented honest-scope), or not a real production defect. Default to REFUTED if it doesn't hold. Use "python -m pytest"/"source .venv/bin/activate"; you may run gh for CI claims.\n\nFINDING ${f.id} (${f.severity}, ${f.dim}): ${f.title}\nLocation: ${f.location}\nClaim: ${f.claim}\nWhy real: ${f.why_real}`,
      { label: `refute:${f.id}`, phase: 'Refute', schema: refuteSchema }
    ).then((v) => ({ ...f, refute: v }))
  )
)
const survivors = judged.filter(Boolean).filter((f) => f.refute && f.refute.verdict === 'STANDS')
const refuted = judged.filter(Boolean).filter((f) => !f.refute || f.refute.verdict === 'REFUTED')
log(`Self-refutation: ${survivors.length} STAND, ${refuted.length} refuted`)
const bySev = (a) => ['critical', 'high', 'medium', 'low'].map((s) => `${s}:${a.filter((f) => f.severity === s).length}`).join(' ')
log(`Survivors — ${bySev(survivors)}`)
return { survivors, refuted_ids: refuted.map((f) => ({ id: f.id, dim: f.dim, why: f.refute && f.refute.reasoning })) }
